function parse(frame) {
  const toBytes = (input) => {
    if (Array.isArray(input)) return input.map((value) => Number(value) & 0xFF);
    if (typeof Uint8Array !== 'undefined' && input instanceof Uint8Array) return Array.from(input);
    if (input && input.buffer instanceof ArrayBuffer) {
      return Array.from(new Uint8Array(input.buffer, input.byteOffset || 0, input.byteLength));
    }
    const text = String(input || '');
    const compactHex = text.trim().replace(/0x/gi, '').replace(/[\s,;:_-]/g, '');
    if (compactHex.length >= 2 && compactHex.length % 2 === 0 && /^[0-9a-f]+$/i.test(compactHex)) {
      const result = [];
      for (let i = 0; i < compactHex.length; i += 2) result.push(parseInt(compactHex.slice(i, i + 2), 16));
      return result;
    }
    const result = [];
    for (let i = 0; i < text.length; i += 1) result.push(text.charCodeAt(i) & 0xFF);
    return result;
  };

  const START = [0x5A, 0xA5, 0xB5, 0x0A, 0x02, 0xDD, 0x80, 0x02];
  const END = [0xDD, 0xEE];
  const FULL_FRAME_LENGTH = 1468;
  const CONTENT_LENGTH = 1458;
  const FRAME_ID_OFFSET = 0;
  const STRAIN_SAMPLES = 160;
  const STRAIN_BYTES = 480;
  const STRAIN1_OFFSET = 4;
  const STRAIN2_OFFSET = STRAIN1_OFFSET + STRAIN_BYTES;
  const STRAIN3_OFFSET = STRAIN2_OFFSET + STRAIN_BYTES;
  const ADC_TEMPERATURE_OFFSET = STRAIN3_OFFSET + STRAIN_BYTES;
  const TMP117_TEMPERATURE_OFFSET = ADC_TEMPERATURE_OFFSET + 3;
  const RESERVED_OFFSET = TMP117_TEMPERATURE_OFFSET + 2;
  const CHECKSUM_OFFSET = RESERVED_OFFSET + 8;

  let bytes = toBytes(frame);
  const startsWith = (array, pattern) => pattern.every((value, index) => array[index] === value);
  const endsWith = (array, pattern) => pattern.every((value, index) => array[array.length - pattern.length + index] === value);

  if (bytes.length === FULL_FRAME_LENGTH && startsWith(bytes, START) && endsWith(bytes, END)) {
    bytes = bytes.slice(START.length, bytes.length - END.length);
  }

  if (bytes.length !== CONTENT_LENGTH) return [];

  const readUInt32LE = (offset) => bytes[offset] + (bytes[offset + 1] * 256) + (bytes[offset + 2] * 65536) + (bytes[offset + 3] * 16777216);
  const readSigned24BE = (offset) => {
    let value = (bytes[offset] * 65536) + (bytes[offset + 1] * 256) + bytes[offset + 2];
    if (value >= 0x800000) value -= 0x1000000;
    return value;
  };
  const readInt16BE = (offset) => {
    let value = (bytes[offset] * 256) + bytes[offset + 1];
    if (value >= 0x8000) value -= 0x10000;
    return value;
  };
  const ads24ToVoltage = (raw) => (raw * 2.5) / 8388608.0;
  const tmp117ToCelsius = (offset) => readInt16BE(offset) * 0.0078125;

  const readStrainArray = (offset) => {
    const values = [];
    for (let i = 0; i < STRAIN_SAMPLES; i += 1) values.push(ads24ToVoltage(readSigned24BE(offset + (i * 3))));
    return values;
  };

  const frameId = readUInt32LE(FRAME_ID_OFFSET);
  const strain1 = readStrainArray(STRAIN1_OFFSET);
  const strain2 = readStrainArray(STRAIN2_OFFSET);
  const strain3 = readStrainArray(STRAIN3_OFFSET);
  const adcTemperature = ads24ToVoltage(readSigned24BE(ADC_TEMPERATURE_OFFSET));
  const tmp117Temperature = tmp117ToCelsius(TMP117_TEMPERATURE_OFFSET);
  const checksum = bytes[CHECKSUM_OFFSET];

  return {
    title: '轴瓦三应变数据',
    datasets: [
      { index: 0, title: '应变1', value: strain1[strain1.length - 1], buffer: strain1, sampleRate: 400 },
      { index: 1, title: '应变2', value: strain2[strain2.length - 1], buffer: strain2, sampleRate: 400 },
      { index: 2, title: '应变3', value: strain3[strain3.length - 1], buffer: strain3, sampleRate: 400 },
      { index: 3, title: '3Byte温度', value: adcTemperature },
      { index: 4, title: '2Byte温度', value: tmp117Temperature }
    ],
    meta: {
      frameId,
      checksum,
      checksumMode: 'read-only',
      frameFormat: '5A A5 B5 0A 02 DD 80 02 + frameId + 3x480B strain + 3B + 2B + 8B + checksum + DD EE'
    }
  };
}

